import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';

export const routes: Routes = [
  { path: '', redirectTo: '/dashboard', pathMatch: 'full' },

  // Auth (public)
  {
    path: 'auth',
    children: [
      { path: 'login',          loadComponent: () => import('./features/auth/login/login').then(m => m.LoginComponent) },
      { path: 'setup-password', loadComponent: () => import('./features/auth/setup-password/setup-password').then(m => m.SetupPasswordComponent) },
    ]
  },

  // Protected — wrapped in Shell layout
  {
    path: '',
    loadComponent: () => import('./layout/shell/shell').then(m => m.ShellComponent),
    canActivate: [authGuard],
    children: [
      { path: 'dashboard',     loadComponent: () => import('./features/dashboard/dashboard').then(m => m.DashboardComponent) },
      { path: 'courses',       loadComponent: () => import('./features/courses/courses').then(m => m.CoursesComponent) },
      { path: 'courses/:courseId/pages',            loadComponent: () => import('./features/courses/pages/course-pages').then(m => m.CoursePagesComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin', 'Instructor'] } },
      { path: 'courses/:courseId/pages/:pageId',    loadComponent: () => import('./features/courses/pages/page-detail').then(m => m.PageDetailComponent) },
      { path: 'courses/:courseId/quizzes',          loadComponent: () => import('./features/courses/quizzes/course-quizzes').then(m => m.CourseQuizzesComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin', 'Instructor'] } },
      { path: 'courses/:courseId/quizzes/:quizId',  loadComponent: () => import('./features/courses/quizzes/quiz-detail').then(m => m.QuizDetailComponent) },
      { path: 'courses/:courseId/assignments/:assignmentId', loadComponent: () => import('./features/courses/assignments/assignment-detail').then(m => m.AssignmentDetailComponent) },
      { path: 'courses/:courseId/grades',           loadComponent: () => import('./features/courses/grades/grades').then(m => m.GradesComponent) },
      { path: 'courses/:id',   loadComponent: () => import('./features/courses/course-detail/course-detail').then(m => m.CourseDetailComponent) },
      { path: 'quiz/:id/edit', loadComponent: () => import('./features/quiz/quiz-editor/quiz-editor').then(m => m.QuizEditorComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin', 'Instructor'] } },
      { path: 'quiz/:id',      loadComponent: () => import('./features/quiz/quiz-attempt/quiz-attempt').then(m => m.QuizAttemptComponent) },
      { path: 'assignments',   loadComponent: () => import('./features/assignments/assignments').then(m => m.AssignmentsComponent) },
      { path: 'gradebook',     loadComponent: () => import('./features/gradebook/gradebook').then(m => m.GradebookComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin', 'Instructor', 'Observer'] } },
      { path: 'certificates',  loadComponent: () => import('./features/certificates/certificates').then(m => m.CertificatesComponent) },
      { path: 'reports',       loadComponent: () => import('./features/reports/reports').then(m => m.ReportsComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin', 'Observer'] } },
      { path: 'users',         loadComponent: () => import('./features/users/users').then(m => m.UsersComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin'] } },
      { path: 'organizations', loadComponent: () => import('./features/organizations/organizations').then(m => m.OrganizationsComponent),
        canActivate: [roleGuard], data: { roles: ['PlatformAdmin'] } },
    ]
  },

  { path: '**', redirectTo: '/dashboard' }
];
