import { HttpInterceptorFn, HttpErrorResponse } from '@angular/common/http';
import { catchError, throwError } from 'rxjs';

export const errorInterceptor: HttpInterceptorFn = (req, next) => {
  return next(req).pipe(
    catchError((err: HttpErrorResponse) => {
      // ASP.NET Core ModelState 400 returns errors as an object: { FieldName: [msgs] }
      // Our ApiResponse.Fail returns errors as a string array.
      const modelStateErrors = err.error?.errors && !Array.isArray(err.error.errors)
        ? Object.entries(err.error.errors)
            .map(([field, msgs]) => `${field}: ${(msgs as string[]).join(', ')}`)
            .join(' | ')
        : null;

      const message =
        (Array.isArray(err.error?.errors) ? err.error.errors[0] : null) ||
        modelStateErrors ||
        err.error?.message ||
        err.error?.title ||
        (err.status ? `HTTP ${err.status}` : 'An unexpected error occurred');
      return throwError(() => new Error(message));
    })
  );
};
