import { HttpInterceptorFn, HttpRequest, HttpHandlerFn, HttpErrorResponse } from '@angular/common/http';
import { inject } from '@angular/core';
import { BehaviorSubject, Observable, catchError, filter, switchMap, take, throwError } from 'rxjs';
import { AuthService } from '../services/auth.service';

// Module-level coordinator. When the first 401 triggers a refresh, every other 401 that
// fires concurrently waits on this subject for the new access token. This avoids the
// rotating-refresh-token race where each parallel request would otherwise refresh with
// the same (now-revoked) refresh token and trigger a spurious logout.
let refreshSubject: BehaviorSubject<string | null> | null = null;

export const jwtInterceptor: HttpInterceptorFn = (req: HttpRequest<unknown>, next: HttpHandlerFn) => {
  const auth = inject(AuthService);
  const token = auth.getAccessToken();

  // withCredentials lets the browser send the HttpOnly refresh cookie on /auth/* calls.
  // The cookie's Path attribute restricts it to /api/auth, so other API calls aren't bloated.
  const authReq = token
    ? req.clone({ setHeaders: { Authorization: `Bearer ${token}` }, withCredentials: true })
    : req.clone({ withCredentials: true });

  return next(authReq).pipe(
    catchError((err: HttpErrorResponse) => {
      // Don't refresh on auth endpoints (would loop) or non-401 errors.
      if (err.status !== 401 || req.url.includes('/auth/')) {
        return throwError(() => err);
      }

      if (refreshSubject) {
        // A refresh is already in flight — wait for its result.
        return waitForRefresh(refreshSubject, req, next);
      }

      // We're the first 401 — start the refresh.
      const subj = new BehaviorSubject<string | null>(null);
      refreshSubject = subj;

      return auth.refresh().pipe(
        switchMap(resp => {
          subj.next(resp.accessToken);
          subj.complete();
          refreshSubject = null;
          const retried = req.clone({
            setHeaders: { Authorization: `Bearer ${resp.accessToken}` },
            withCredentials: true
          });
          return next(retried);
        }),
        catchError(refreshErr => {
          // Refresh token is invalid/expired → propagate failure to all waiting requests
          // and sign the user out so they end up on the login page.
          subj.error(refreshErr);
          refreshSubject = null;
          auth.logout();
          return throwError(() => refreshErr);
        })
      );
    })
  );
};

function waitForRefresh(
  subj: BehaviorSubject<string | null>,
  req: HttpRequest<unknown>,
  next: HttpHandlerFn
): Observable<any> {
  return subj.pipe(
    filter(t => t !== null),
    take(1),
    switchMap(newToken => {
      const retried = req.clone({
        setHeaders: { Authorization: `Bearer ${newToken}` },
        withCredentials: true
      });
      return next(retried);
    })
  );
}
